void Spark::paint(pro2::Window& window) const {
    const pro2::Pt pt = toPt(pos_);
    pro2::Pt topleft = {pt.x - 7, pt.y - 9};
    paint_sprite(window, topleft, spark_sprite_normal_, true);
}

void Spark::apply_physicis(){
    const int gravity = 1;
   pos_.x += speed_.x;
   pos_.y += speed_.y;
    
}


void Spark::update(pro2::Window& window){
    last_pos_ = pos_;
    apply_physicis();    
}   

bool Spark::mario_killed(const pro2::Rect& rmario){
    return rect_touch(rmario,get_rect());
}



