void Bowser::paint(pro2::Window& window) const {
    const pro2::Pt topleft = {pos_.x -32, pos_.y - 55};
    paint_sprite(window, topleft, bowser_sprite_normal_, not looking_left_);
    
    
    for(const Spark& s : sparks_) {
        s.paint(window);
    }

}

void Bowser::apply_physics_() {
    if (grounded_) {
        speed_.y = 0;
        accel_.y = 0;
    }

    const int gravity = 1;  
    speed_.y += gravity;

    if (accel_time_ > 0) {
        speed_.y += accel_.y;
        accel_time_--;
    }

    pos_.x += speed_.x;
    pos_.y += speed_.y;
}

void Bowser::jump() {
    if (grounded_) {
        accel_.y = -7;
        grounded_ = false;
        accel_time_ = 2;
    }
}

void Bowser::update_platform(std::set<Platform*>& queryplat){
    for (Platform* platform : queryplat) {
        if (not grounded_ and rect_touch(get_rect(), platform->get_rect())) {
            jump();
        }
        if ((*platform).has_crossed_floor_downwards(last_pos_, pos_)) {
            set_grounded(true);
            set_y((*platform).top());
        }

        if((*platform).has_crossed_floor_horizontall(last_pos_, pos_)){
            pro2::Rect prect = platform->get_rect();
            int height = platform->bottom() - platform->top();
            //hascrossed left
            if(rect_touch(get_rect(), prect)){
                
                if(last_pos_.x <= prect.left and pos_.x <= prect.right){
                    
                    set_x(prect.left - 20);
                    
                }
                else if(last_pos_.x >= prect.right and  pos_.x >= prect.left){
                   
                    set_x(prect.right + 20);
                }
            }

        }
      
    }
    
}
void Bowser::update_cfloor(std::set<Circuitfloor*>& cfloor){
    for(Circuitfloor* cf : cfloor){

        if((*cf).has_crossed_floor_downwards(last_pos_, pos_)){
            set_grounded(true);
            set_y((*cf).top());
        }
        
    }
}

void Bowser::update(pro2::Window& window, std::set<Platform*>& queryplat, std::set<Circuitfloor*>& cfloor,const  pro2::Rect& rmario, bool& mkilled) {
    last_pos_ = pos_;
    speed_.x = 0; 
    
    int mpos_y = rmario.top;
    int mpos_x = rmario.left;
    
    if (std::abs(pos_.y - mpos_y) <= 150 and abs(pos_.x - mpos_x) <= 160) {
        if (pos_.x < mpos_x) {
            speed_.x = 1; 
        } else if (pos_.x > mpos_x) {
            speed_.x = -1; 
        }
    }

    if (speed_.x != 0) {
        looking_left_ = speed_.x < 0;
    }
    

    // Apply acceleration and speed
    apply_physics_();
    
    // Check position
    set_grounded(false);
    
    update_cfloor(cfloor);
    update_platform(queryplat);
    //Metode per matar a mario
    mkilled = false;
    for(Spark& s : sparks_) {
        s.update(window);
        if(s.mario_killed(rmario)) {
            mkilled = true;
            return;
        }
    }
    
    //salta cada 5 sec
    if (window.frame_count() % 240 == 0 and grounded_) {
        jump();
    }

}

void Bowser::launch_spark(const pro2::Rect& rmario) {
    pro2::Ptd m = {(double) (rmario.left+rmario.right)/2, (double)(rmario.top+rmario.bottom)/2};
    pro2::Ptd p = {(double) pos_.x,  (double)pos_.y -24};
    sparks_.push_back(Spark(p,m));
    
}

bool Bowser::mario_has_crossed_downwards(pro2::Pt plast, pro2::Pt pcurr) const{
    pro2::Rect bowserhb = get_rect();
    return (bowserhb.left <= plast.x && plast.x <= bowserhb.right) && (bowserhb.left <= pcurr.x && pcurr.x <= bowserhb.right) &&
    (plast.y <= bowserhb.top && pcurr.y >= bowserhb.top);
}

